`,o.jsxs(i.li,{children:["a simple HTML template with a ",o.jsx(i.code,{children:"<canvas>"})," element for graphics"]}),`
`,o.jsxs(i.li,{children:["a CSS file that stretched the ",o.jsx(i.code,{children:"<canvas>"})," to the screen's size"]}),`
