`,o.jsx(i.p,{children:"You have developed quads of steel, and you are very experienced with managing risk, rockfall, and exposure."}),`
`,o.jsx(i.h3,{children:"Mt. Olympus - West Slabs"}),`
`,o.jsx(i.h3,{children:"The South Ridge of Superior"}),`
